import { formatPrice } from '../utils/helpers';

interface Product {
  id: string;
  name: string;
  price: number;
  imageUrl: string;
}

const ProductCard = ({ product }: { product: Product }) => (
  <div className="group relative bg-gray-800/60 border border-gray-700/50 rounded-2xl p-6 cursor-pointer hover:border-indigo-500/50 hover:bg-gray-800 transition-all duration-200">
    <img src={product.imageUrl} alt={product.name} className="w-full h-48 object-cover rounded-xl mb-4" />
    <h3 className="text-white font-medium mb-1">{product.name}</h3>
    <p className="text-indigo-400 text-lg">{formatPrice(product.price)}</p>
  </div>
);

export default ProductCard;

