import { useCart } from '../hooks/useCart';

interface CartItemProps {
  item: {
    id: string;
    name: string;
    price: number;
    quantity: number;
    imageUrl: string;
  };
}

const CartItem = ({ item }: CartItemProps) => {
  const { updateQuantity, removeItem } = useCart();

  return (
    <div className="flex items-center gap-4 p-4 border-b border-gray-800">
      <img src={item.imageUrl} alt={item.name} className="w-16 h-16 object-cover rounded-lg" />
      <div className="flex-1">
        <h4 className="text-white font-medium">{item.name}</h4>
        <p className="text-gray-400">{item.quantity} x ${item.price.toFixed(2)}</p>
      </div>
      <div className="flex items-center gap-2">
        <button onClick={() => updateQuantity(item.id, item.quantity - 1)} className="px-2 py-1 bg-gray-700 text-white rounded hover:bg-gray-600 transition">
          -
        </button>
        <span className="text-white">{item.quantity}</span>
        <button onClick={() => updateQuantity(item.id, item.quantity + 1)} className="px-2 py-1 bg-gray-700 text-white rounded hover:bg-gray-600 transition">
          +
        </button>
        <button onClick={() => removeItem(item.id)} className="px-2 py-1 bg-red-600 text-white rounded hover:bg-red-500 transition">
          Remove
        </button>
      </div>
    </div>
  );
};

export default CartItem;

